#!/usr/bin/env bash
set -euo pipefail

INSTALL_ROOT="${HOME}/.local/share/aster-browser-portable"
APP_DIR="${INSTALL_ROOT}/app"
RUNTIME_DIR="${INSTALL_ROOT}/runtime"
VENV_DIR="${RUNTIME_DIR}/venv"
STATE_DIR="${INSTALL_ROOT}/state"
CONFIG_FILE="${STATE_DIR}/config/config.json"
LAUNCHER="${INSTALL_ROOT}/aster-launch.sh"
DESKTOP_DIR="${HOME}/.local/share/applications"
DESKTOP_FILE="${DESKTOP_DIR}/org.aster.Browser.desktop"
ICON_FILE="${APP_DIR}/packaging/linux/aster.svg"
ARCHIVE_LINE=$(awk '/^__ARCHIVE_BELOW__$/{print NR + 1; exit 0;}' "$0")
RUN_AFTER=1
EXTRACT_ONLY=0

for arg in "$@"; do
  case "$arg" in
    --no-run) RUN_AFTER=0 ;;
    --extract-only) EXTRACT_ONLY=1; RUN_AFTER=0 ;;
  esac
done

msg() { printf '[Aster Black Arc Installer] %s\n' "$*"; }
die() { printf '[Aster Black Arc Installer] %s\n' "$*" >&2; exit 1; }

PYTHON_BIN=""
for candidate in python3 python; do
  if command -v "$candidate" >/dev/null 2>&1; then
    PYTHON_BIN="$candidate"
    break
  fi
done
[[ -n "$PYTHON_BIN" ]] || die "Python 3 was not found on this system."

TMP_DIR=$(mktemp -d)
trap 'rm -rf "$TMP_DIR"' EXIT
mkdir -p "$INSTALL_ROOT" "$RUNTIME_DIR" "$STATE_DIR"

tail -n +"$ARCHIVE_LINE" "$0" | base64 -d > "$TMP_DIR/app.tar.gz"
tar -xzf "$TMP_DIR/app.tar.gz" -C "$TMP_DIR"
SRC_DIR="$TMP_DIR/aster_patch"
[[ -d "$SRC_DIR" ]] || die "App archive was extracted but the source directory is missing."

msg "Extracting updated app..."
rm -rf "$APP_DIR"
mkdir -p "$APP_DIR"
cp -a "$SRC_DIR"/. "$APP_DIR"/

if [[ "$EXTRACT_ONLY" -eq 1 ]]; then
  msg "Extract-only mode complete."
  exit 0
fi

if [[ ! -x "$VENV_DIR/bin/python" ]]; then
  msg "Creating Python virtual environment..."
  "$PYTHON_BIN" -m venv "$VENV_DIR"
fi

msg "Installing or updating Python dependencies..."
"$VENV_DIR/bin/python" -m pip install --upgrade pip >/dev/null
"$VENV_DIR/bin/python" -m pip install -r "$APP_DIR/requirements-lock.txt"

msg "Writing launcher..."
cat > "$LAUNCHER" <<EOF
#!/usr/bin/env bash
set -euo pipefail
export QT_AUTO_SCREEN_SCALE_FACTOR=1
exec "$VENV_DIR/bin/python" "$APP_DIR/run_aster.py" "\$@"
EOF
chmod +x "$LAUNCHER"

msg "Updating default config..."
mkdir -p "$(dirname "$CONFIG_FILE")"
CONFIG_FILE="$CONFIG_FILE" "$VENV_DIR/bin/python" - <<'PY'
import json
import os
from pathlib import Path
path = Path(os.environ['CONFIG_FILE'])
data = {}
if path.exists():
    try:
        data = json.loads(path.read_text(encoding='utf-8'))
    except Exception:
        data = {}
if not isinstance(data, dict):
    data = {}
data['theme'] = 'black_arc'
data.setdefault('active_tab_left_click_menu', True)
path.write_text(json.dumps(data, indent=2, sort_keys=True), encoding='utf-8')
PY

msg "Writing desktop entry..."
mkdir -p "$DESKTOP_DIR"
cat > "$DESKTOP_FILE" <<EOF
[Desktop Entry]
Type=Application
Name=Aster Browser
Comment=Low-RAM Linux browser with internal assistant
Exec=$LAUNCHER %U
Icon=$ICON_FILE
Terminal=false
Categories=Network;WebBrowser;
StartupNotify=true
MimeType=text/html;x-scheme-handler/http;x-scheme-handler/https;
EOF

msg "Installation or update complete."
msg "Launcher: $LAUNCHER"

if [[ "$RUN_AFTER" -eq 1 ]]; then
  msg "Starting Aster..."
  exec "$LAUNCHER"
fi
exit 0
__ARCHIVE_BELOW__
